.darma-loader-darma-custom-332 {color: var(--loader-color, #e11d48);
  --loader-secondary-color: var(--loader-secondary-color, #fb7185);
  --loader-bg: var(--loader-bg, #ffffff);
  height: 70px;
  aspect-ratio: 1;
  padding: 10px;
  border-radius: 50%;
  box-sizing: border-box;
  position: relative;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  filter: blur(12px);
}.darma-loader-darma-custom-332:before {content: "";
  position: absolute;
  inset: 0;
  background: conic-gradient(#0000 35%,var(--loader-color, #e11d48),#0000 65%);
  animation: darma-loader-darma-custom-332-l1 1.5s linear infinite;
}@keyframes darma-loader-darma-custom-332-l1 {to {rotate: 1turn}}

